  ('real-estate-appraiser-moex-00364', 'real-estate-appraiser', 'real-estate-appraiser-moex-100-ba81c82b', 'sub-real-estate-appraiser-04', NULL, 'essay', '國內有不動產市場專家認為「特種貨物及勞務稅條例」之施行，將有助於降低住宅
的假性需求，此時對於國內住宅不動產交易量與價格有何影響？若今有顯著比例之
住宅不動產持有人為規避特種貨物及勞務稅之負擔而延緩賣屋時間，此一情形又將
如何影響住宅不動產交易量與價格？試繪圖說明之。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:06+00:00", "source_pdf_sha1": "6ab6530f9509", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "905", "s": "0805", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "不動產經濟學", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00365', 'real-estate-appraiser', 'real-estate-appraiser-moex-100-ba81c82b', 'sub-real-estate-appraiser-04', NULL, 'essay', '假設水稻田大規模地轉變為建地使用後，所喪失之地下水補注以及地區性洪水調節
等作用，必須投入龐大經費興建水庫及防洪工程等方式予以彌補。若今考慮前述工
程成本，水稻田開發為建地的數量會如何變化？試繪圖說明之。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:06+00:00", "source_pdf_sha1": "6ab6530f9509", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "905", "s": "0805", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "不動產經濟學", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00366', 'real-estate-appraiser', 'real-estate-appraiser-moex-100-ba81c82b', 'sub-real-estate-appraiser-04', NULL, 'essay', '土地利用規劃管制嚴格程度通常會影響土地的經濟供給。假設甲、乙二區有相同的
條件，惟甲區的土地利用規劃管制較乙區為嚴，又假設甲、乙二區住宅用地的均衡
價格與使用面積水準相同。若今甲、乙二區均因居民所得提高而增加對住宅用地之
需求，此將如何影響甲、乙二區住宅用地均衡價格與使用面積？請將甲、乙二區情
形繪於同一個經濟分析圖中進行比較分析。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:06+00:00", "source_pdf_sha1": "6ab6530f9509", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "905", "s": "0805", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "不動產經濟學", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00367', 'real-estate-appraiser', 'real-estate-appraiser-moex-100-ba81c82b', 'sub-real-estate-appraiser-04', NULL, 'essay', '土地增值稅可能發生轉嫁，今假設以實際交易價格為土地增值稅之課稅依據，若本
次實際交易價格是前次實際交易價格的一倍（實際增值百分之一百），在其他條件
不變的情形下，對實際增值課以百分之二十的稅率。請問在什麼情形下，土地增值
稅不會轉嫁？又在什麼情形下，買方雖無需負擔全部的土地增值稅，但其分擔的稅
額會高於賣方？試繪圖說明之。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:06+00:00", "source_pdf_sha1": "6ab6530f9509", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "905", "s": "0805", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "不動產經濟學", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00368', 'real-estate-appraiser', 'real-estate-appraiser-moex-100-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '陳子昂作〈登幽州臺歌〉：「前不見古人，後不見來者。念天地之悠悠，獨愴然而涕下。」以抒發其面 對時間的恆長，而意識到人生命短暫孤寂的悲嘆感情。下列詩文所流露的情感與此最相近的是：', '["知天之長，而吾所歷者短，則遇憂患橫逆之來，當少忍以待其定（曾國藩《曾國藩日記》）", "人生只似風前絮，歡也零星，悲也零星，都作連江點點萍（王國維〈採桑子〉）", "死生，命也，其有夜旦之常，天也。人之有所不得與，皆物之情也（《莊子．大宗師》）", "老驥伏櫪，志在千里。烈士暮年，壯心不已（曹操〈步出夏門行．龜雖壽〉）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:06+00:00", "source_pdf_sha1": "7cdb41681d05", "answer_pdf_sha1": "a0a9d5185232", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "905", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00369', 'real-estate-appraiser', 'real-estate-appraiser-moex-100-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '下列詩歌，流露出批判戰爭的選項是：', '["漢家旌旗滿陰山，不遣胡兒馬匹還。願得此身長報國，何須生入玉門關（戴叔倫〈塞上曲〉）", "弓背霞明劍照霜，秋風走馬出咸陽。未收天子河 湟地，不擬回頭望故鄉（令狐楚〈少年行〉）", "何代何王不戰爭？盡從離亂見清平。如今暴骨多於土，猶點鄉兵作戍兵（韋莊〈憫耕者〉）", "金帶連環束戰袍，馬頭衝雪度臨洮。捲旗夜劫單于帳，亂斫胡兒缺寶刀（馬戴〈出塞詞〉）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:06+00:00", "source_pdf_sha1": "7cdb41681d05", "answer_pdf_sha1": "a0a9d5185232", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "905", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00370', 'real-estate-appraiser', 'real-estate-appraiser-moex-100-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '①萬木凍欲折，孤根暖獨回。前村深雪裡，昨夜一枝開', '["一樹春風千萬枝，嫩于金色軟于絲。永豐西角荒園裡，盡日無人屬阿誰", "自讀西湖處士詩，年年臨水看幽姿。晴窗畫出橫斜影，絕勝前村夜雪時", "嫋嫋古堤邊，青青一數煙。若為絲不斷，留取繫郎船 ⑤含煙惹霧每依依，萬緒千條拂落暉。為報行人休盡折，半留相送半迎歸 ⑥愁鎖巴雲往事空，只將遺恨寄芳叢。歸心千古終難白，啼血萬山都是紅 上列詩句，描摹柳樹的是：", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:06+00:00", "source_pdf_sha1": "7cdb41681d05", "answer_pdf_sha1": "a0a9d5185232", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "905", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00371', 'real-estate-appraiser', 'real-estate-appraiser-moex-100-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '①以五十步笑百步，則何如？曰：不可，「直」不百步耳，是亦走也（《孟子．梁惠王》）／寡人非能 好先王樂也，「直」好世俗之樂耳（《孟子．梁惠王》）', '["「歸」於汪，汪故貧，先君子以為贅婿（汪中〈先母鄒孺人靈表〉）／句踐之困於會稽，而「歸」臣 妾於吳（《史記．越王句踐世家》）", "燕趙處秦革滅「殆」盡之際，可謂智力孤危（蘇洵〈六國論〉）／學而不思則罔，思而不學則「殆」 （《論語．為政》）", "當二公之初守也，寧能知人之卒不救，棄城而「逆」遁（韓愈〈張中丞傳後敘〉）／眾人所趨，勢之 所歸，雖有大力莫之敢「逆」（曾國藩〈原才〉） ⑤小學而大「遺」，吾未見其明也（韓愈〈師說〉）／君子篤於親，則民興於仁；故舊不「遺」，則民 不偷。（《論語．泰伯》） ⑥匣而埋諸土，年出之，抱以「適」市（劉基《郁離子》）／使其中坦然，不以物傷性，將何「適」而 非快（蘇轍〈黃州快哉亭記〉） 以上各組文句「」內字義相同的選項是：", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:06+00:00", "source_pdf_sha1": "7cdb41681d05", "answer_pdf_sha1": "a0a9d5185232", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "905", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00372', 'real-estate-appraiser', 'real-estate-appraiser-moex-100-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '辛棄疾〈鷓鴣天〉：「壯歲旌旗擁萬夫，錦襜突騎渡江初。燕兵夜娖銀胡籙，漢箭朝飛金僕姑。追往事， 嘆今吾，春風不染白髭鬚。卻將萬字平戎策，換得東家種樹書」，此闋詞所傳達的情境，下列何者最為 妥適？', '["曉戰隨金鼓，宵眠抱玉鞍。願將腰下劍，直為斬樓蘭", "昔時飛箭無全目，今日垂楊生左肘。路旁時賣故侯瓜，門前學種先生柳", "大漠孤煙直，長河落日圓。蕭關逢候騎，都護在燕然", "青海長雲暗雪山，孤城遙望玉門關。黃沙百戰穿金甲，不破樓蘭終不還"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:06+00:00", "source_pdf_sha1": "7cdb41681d05", "answer_pdf_sha1": "a0a9d5185232", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "905", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL)
